import {{ Injectable }} from '@nestjs/common';
import {{ UserService }} from './models/user.model';
import {{ UserServiceRepository }} from './repositories/user.repository';

@Injectable()
export class UserServiceService {{
  constructor(
    private readonly repository: UserServiceRepository,
  ) {{}}

  async findAll(): Promise<UserService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<UserService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<UserService>): Promise<UserService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<UserService>): Promise<UserService> {{
    return this.repository.update(id, data);
  }}
}}
